    16|  const [loaded, setLoaded] = useState(false)
    17|
    18|  useEffect(() => {
    19|    try {
    20|      const saved = localStorage.getItem(STORAGE_KEY)
    21|      if (saved) setItems(JSON.parse(saved))
    22|    } catch {}
    23|    setLoaded(true)
